1	package com.coding.assistant.security;
2	
3	import jakarta.servlet.DispatcherType;
4	import lombok.RequiredArgsConstructor;
5	import org.springframework.context.annotation.Bean;
6	import org.springframework.context.annotation.Configuration;
7	import org.springframework.security.authentication.AuthenticationManager;
8	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
9	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
10	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
11	import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
12	import org.springframework.security.config.http.SessionCreationPolicy;
13	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
14	import org.springframework.security.crypto.password.PasswordEncoder;
15	import org.springframework.security.web.SecurityFilterChain;
16	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
17	import org.springframework.web.cors.CorsConfiguration;
18	import org.springframework.web.cors.CorsConfigurationSource;
19	import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
20	
21	import java.util.Arrays;
22	import java.util.List;
23	
24	@Configuration
25	@EnableWebSecurity
26	@RequiredArgsConstructor
27	public class SecurityConfig {
28	
29	    private final JwtAuthenticationFilter jwtAuthenticationFilter;
30	
31	    @Bean
32	    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
33	        http
34	                .csrf(AbstractHttpConfigurer::disable)
35	                .cors(cors -> cors.configurationSource(corsConfigurationSource()))
36	                .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
37	                .exceptionHandling(ex -> ex
38	                        .authenticationEntryPoint((request, response, authException) -> {
39	                            response.setStatus(401);
40	                            response.setContentType("application/json;charset=UTF-8");
41	                            response.getWriter().write("{\"code\":401,\"message\":\"未登录或登录已过期\",\"data\":null}");
42	                        })
43	                )
44	                .authorizeHttpRequests(auth -> auth
45	                        .dispatcherTypeMatchers(DispatcherType.ASYNC).permitAll()
46	                        .requestMatchers("/api/auth/register", "/api/auth/login").permitAll()
47	                        .requestMatchers("/uploads/**").permitAll()
48	                        .requestMatchers("/api/**").authenticated()
49	                        .anyRequest().permitAll()
50	                )
51	                .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
52	
53	        return http.build();
54	    }
55	
56	    @Bean
57	    public CorsConfigurationSource corsConfigurationSource() {
58	        CorsConfiguration configuration = new CorsConfiguration();
59	        configuration.setAllowedOriginPatterns(List.of("*"));
60	        configuration.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS", "PATCH"));
61	        configuration.setAllowedHeaders(List.of("*"));
62	        configuration.setAllowCredentials(true);
63	        configuration.setMaxAge(3600L);
64	
65	        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
66	        source.registerCorsConfiguration("/**", configuration);
67	        return source;
68	    }
69	
70	    @Bean
71	    public PasswordEncoder passwordEncoder() {
72	        return new BCryptPasswordEncoder();
73	    }
74	
75	    @Bean
76	    public AuthenticationManager authenticationManager(AuthenticationConfiguration authConfig) throws Exception {
77	        return authConfig.getAuthenticationManager();
78	    }
79	}
